import React, { useState, useRef, useEffect } from 'react';
import './css_comp/result_train.css';
import Seat_selection from './seat_selection';

export default function Result_train() {
  const showClassInfo = useRef(null);
  const seat_Show = useRef(null);
  const [show, setShow] = useState(false);
  const [showSeat, setshowSeat] = useState(false);

  // Handles the seat selection box height based on `showSeat` state
  useEffect(() => {
    const seat_show = seat_Show.current;

    // Ensure the ref exists and then apply height
    if (seat_show) {
      if (showSeat) {
        seat_show.style.maxHeight = `${seat_show.scrollHeight}px`;
      } else {
        seat_show.style.maxHeight = '0px';
      }
    }
  }, [showSeat]); // Effect runs when showSeat changes

  // Handles the class info box height based on `show` state
  useEffect(() => {
    const class_info = showClassInfo.current;

    // Ensure the ref exists and apply height
    if (class_info) {
      if (show) {
        class_info.style.maxHeight = `${class_info.scrollHeight}px`;
      } else {
        class_info.style.maxHeight = '0px';
      }
    }
  }, [show]);

  // Use effect to ensure initial mount works well
  useEffect(() => {
    const seat_show = seat_Show.current;
    if (seat_show) {
      // Set initial maxHeight after mount based on state
      seat_show.style.maxHeight = showSeat ? `${seat_show.scrollHeight}px` : '0px';
    }
  }, []); // This effect runs only once on initial load
    return (
        <div>
            <div className='train-info'>
                <div className='train-name' onClick={()=>setShow(!show)}>
                    <h3>Parabot Express</h3>
                    <i className={`up-down fa-solid fa-angle-up ${show? 'up-down-active':''}`} style={{ color: '#eaae0b' }}></i>
                </div>
                <div className={`class-info`} ref={showClassInfo}>
                    <div className='train-timing-details'>
                        <div className='time'>
                            <div>
                                <div>
                                    <span>27 SEP,</span>
                                    <span>06:30 AM</span>
                                </div>
                                <div>
                                    Dhaka
                                </div>
                            </div>

                            <div>
                                <div>
                                    <span>27 SEP,</span>
                                    <span>01:00 AM</span>
                                </div>
                                <div>
                                    Sylhet
                                </div>
                            </div>


                        </div>
                        <div className='train-details'>
                            <i className="fa-solid fa-location-dot"></i>
                            <h4>Train Details</h4>

                        </div>

                    </div>
                    <div className='all-classes'>
                        <div className='classes'>
                            <div className='classes-info-1'>
                                <h3>SNIGDHA</h3>
                                <h4 id='green'>৳719</h4>
                                <p id='vat'>Including vat</p>
                            </div>
                            <hr id='horizontal-line' />
                            <div className='classes-info-2'>
                                <p>Available Tickets <br />
                                (Counter + Online)</p>
                                <h3 id='greeen'>4</h3>
                                <button className='class-btn' onClick={()=>setshowSeat(!showSeat)} >BOOK NOW</button>
                            </div>
                        </div>


                        <div className='classes'>
                            <div className='classes-info-1'>
                                <h3>AC-B</h3>
                                <h4 id='green'>৳719</h4>
                                <p id='vat'>Including vat</p>
                            </div>
                            <hr id='horizontal-line' />
                            <div className='classes-info-2'>
                                <p>Available Tickets <br />
                                (Counter + Online)</p>
                                <h3 id='greeen'>4</h3>
                                <button className='class-btn'>BOOK NOW</button>
                            </div>
                        </div>



                        <div className='classes'>
                            <div className='classes-info-1'>
                                <h3>SHOVON</h3>
                                <h4 id='green'>৳719</h4>
                                <p id='vat'>Including vat</p>
                            </div>
                            <hr id='horizontal-line' />
                            <div className='classes-info-2'>
                                <p>Available Tickets <br />
                                (Counter + Online)</p>
                                <h3 id='greeen'>4</h3>
                                <button className='class-btn'>BOOK NOW</button>
                            </div>
                        </div>


                    </div>

                    <div ref={seat_Show} className='seat_show'>
                        {showSeat && <Seat_selection/>}
                        

                       
                    </div>
                    



                    <div>



                    </div>

                </div>
            </div>


        </div>
    )
}
